mapper.select:
SELECT r.id, r.album_id, r.title, r.content, r.cover_image, COALESCE(LEAST(10.0, AVG(c.score)), r.score) AS score, r.publish_time, r.update_time, u.username AS author_name, a.title AS album_title, a.artist, a.genre, a.release_date FROM review r LEFT JOIN user u ON u.id = r.author_id LEFT JOIN album a ON a.id = r.album_id LEFT JOIN comment c ON c.content_id = r.id AND c.content_type = 'REVIEW' AND c.score IS NOT NULL WHERE r.status = 'PUBLISHED'
AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%') OR a.artist LIKE CONCAT('%', #{keyword}, '%'))
AND FIND_IN_SET(#{genre}, REPLACE(a.genre, ', ', ',')) > 0
AND r.score >= #{minScore}
AND r.score <= #{maxScore}
GROUP BY r.id, r.album_id, r.title, r.content, r.cover_image, r.score, r.publish_time, r.update_time, u.username, a.title, a.artist, a.genre, a.release_date ORDER BY r.publish_time DESC, score DESC

SELECT r.id, r.album_id, r.title, r.content, r.cover_image, COALESCE(LEAST(10.0, AVG(c.score)), r.score) AS score, r.publish_time, r.update_time, u.username AS author_name, a.title AS album_title, a.artist, a.genre, a.release_date FROM review r LEFT JOIN user u ON u.id = r.author_id LEFT JOIN album a ON a.id = r.album_id LEFT JOIN comment c ON c.content_id = r.id AND c.content_type = 'REVIEW' AND c.score IS NOT NULL WHERE 1 = 1
AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%') OR a.artist LIKE CONCAT('%', #{keyword}, '%'))
AND FIND_IN_SET(#{genre}, REPLACE(a.genre, ', ', ',')) > 0
AND r.score >= #{minScore}
AND r.score <= #{maxScore}
GROUP BY r.id, r.album_id, r.title, r.content, r.cover_image, r.score, r.publish_time, r.update_time, u.username, a.title, a.artist, a.genre, a.release_date ORDER BY r.publish_time DESC, r.id DESC
